El formato CSV
El CSV (valores separados por comas) es el formato más común para datos tabulares: cada línea es un registro y los campos van separados por comas. Es lo que exportan las hojas de cálculo. Para leerlo, separamos cada línea con split(","), el método de cadena que conocemos:

def leer_csv(ruta):
    registros = []
    try:
        with open(ruta, "r", encoding="utf-8") as f:
            lineas = [linea.strip() for linea in f if linea.strip() != ""]
    except FileNotFoundError:
        raise FileNotFoundError(f"No se encontró el archivo: {ruta}")

    if not lineas:
        return []

    encabezado = lineas[0].split(",")          # primera línea: nombres de columna
    for linea in lineas[1:]:
        valores = linea.split(",")
        registro = {}
        for clave, valor in zip(encabezado, valores):
            registro[clave] = valor
        registros.append(registro)
    return registros


