Ejemplo integrador
Cerramos la lección, y la etapa de Python puro, con un programa que reúne casi todo: lee un CSV de calificaciones, organiza los datos en objetos usando una clase, calcula estadísticas con un módulo y guarda el resultado como JSON.

import json
import statistics


class Estudiante:
    def __init__(self, nombre, carrera, calificacion):
        self.nombre = nombre
        self.carrera = carrera
        self.calificacion = calificacion

    def clasificar(self):
        if self.calificacion &gt;= 9.0:
            return "Sobresaliente"
        elif self.calificacion &gt;= 7.0:
            return "Bien"
        elif self.calificacion &gt;= 6.0:
            return "Suficiente"
        else:
            return "Reprobado"


def leer_csv(ruta):
    with open(ruta, "r", encoding="utf-8") as f:
        lineas = [linea.strip() for linea in f if linea.strip() != ""]
    encabezado = lineas[0].split(",")
    registros = []
    for linea in lineas[1:]:
        valores = linea.split(",")
        registro = {}
        for clave, valor in zip(encabezado, valores):
            registro[clave] = valor
        registros.append(registro)
    return registros


def analizar(ruta_csv, ruta_salida):
    # Leer el CSV y construir objetos Estudiante
    registros = leer_csv(ruta_csv)
    estudiantes = []
    for r in registros:
        try:
            estudiantes.append(Estudiante(r["nombre"], r["carrera"], float(r["calificacion"])))
        except ValueError:
            print(f"Calificación inválida para {r['nombre']}, se omite.")

    # Estadísticas por carrera
    carreras = {e.carrera for e in estudiantes}
    resultado = {}
    for carrera in sorted(carreras):
        califs = [e.calificacion for e in estudiantes if e.carrera == carrera]
        alumnos = [
            {"nombre": e.nombre, "calificacion": e.calificacion, "nivel": e.clasificar()}
            for e in estudiantes if e.carrera == carrera
        ]
        resultado[carrera] = {
            "promedio": round(statistics.mean(califs), 2),
            "total": len(califs),
            "alumnos": alumnos,
        }

    # Guardar como JSON
    with open(ruta_salida, "w", encoding="utf-8") as f:
        json.dump(resultado, f, ensure_ascii=False, indent=4)

    return resultado


reporte = analizar("leccion_calificaciones.csv", "leccion_reporte.json")

for carrera in reporte:
    datos = reporte[carrera]
    print(f"\n{carrera} — promedio {datos['promedio']} ({datos['total']} alumnos)")
    for alumno in datos["alumnos"]:
        print(f"  {alumno['nombre']:&lt;8} {alumno['calificacion']}  {alumno['nivel']}")


